import { forwardRef, useRef, type ReactNode } from "react";
import { clsx } from "clsx";
import {
  Dialog,
  Modal as AriaModal,
  ModalOverlay,
  type ModalOverlayProps,
} from "react-aria-components";
import { ModalContext } from "./ModalContext";
import { ModalHeader } from "./components/ModalHeader";
import { ModalBody } from "./components/ModalBody";
import { ModalFooter } from "./components/ModalFooter";
import { useDraggableModal } from "./hooks/useDraggableModal";
import * as styles from "./Modal.css";
import {
  DEFAULT_MODAL_WIDTH,
  DEFAULT_MODAL_PLACEMENT,
  DEFAULT_MODAL_MAX_HEIGHT,
  type ModalPlacement,
  type ModalWidth,
  type ModalMaxHeight,
} from "./Modal.config";

// Re-export subcomponent types
export type { ModalHeaderProps } from "./components/ModalHeader";
export type { ModalBodyProps } from "./components/ModalBody";
export type { ModalFooterProps } from "./components/ModalFooter";

// ============================================================================
// Modal (Main Component)
// ============================================================================

interface ModalCustomProps {
  /**
   * Whether the modal is open
   */
  open: boolean;

  /**
   * Called when the open state changes
   */
  onOpenChange: (open: boolean) => void;

  /**
   * The placement of the modal
   * @default 'bottom'
   */
  placement?: ModalPlacement;

  /**
   * The width of the modal. Only applies when placement is 'center'.
   * The modal will never exceed calc(100vw - 2rem) regardless of this value.
   * @default 'md'
   */
  width?: ModalWidth;

  /**
   * The maximum height of the modal.
   * The modal will never exceed calc(100svh - 2rem) regardless of this value.
   * @default 'full'
   */
  maxHeight?: ModalMaxHeight;

  /**
   * Whether the modal can be dismissed by clicking outside or pressing Escape
   * @default true
   */
  dismissable?: boolean;

  /**
   * Whether the modal displays a drag indicator. Only applies when placement is 'bottom'.
   * @default false
   */
  draggable?: boolean;

  /**
   * The content of the modal (typically Modal.Header, Modal.Body, Modal.Footer)
   */
  children: ReactNode;
}

export interface ModalProps
  extends Omit<ModalOverlayProps, keyof ModalCustomProps>, ModalCustomProps {}

const ModalRoot = forwardRef<HTMLDivElement, ModalProps>(
  (
    {
      open,
      onOpenChange,
      placement = DEFAULT_MODAL_PLACEMENT,
      width = DEFAULT_MODAL_WIDTH,
      maxHeight = DEFAULT_MODAL_MAX_HEIGHT,
      dismissable = true,
      draggable = false,
      children,
      className,
      ...props
    },
    ref
  ) => {
    const handleClose = () => {
      onOpenChange(false);
    };

    // Internal ref for measuring modal height
    const internalModalRef = useRef<HTMLDivElement | null>(null);

    // Drag-to-dismiss only applies when draggable and placement is bottom
    const isDragEnabled = draggable && placement === "bottom";

    const {
      dragProps,
      style: modalStyle,
      bodyRef,
    } = useDraggableModal({
      enabled: isDragEnabled,
      open,
      onDismiss: handleClose,
      modalRef: internalModalRef,
    });

    return (
      <ModalOverlay
        isOpen={open}
        onOpenChange={onOpenChange}
        isDismissable={dismissable}
        className={clsx(styles.overlay({ placement }), className)}
        {...props}
      >
        <AriaModal
          ref={(node) => {
            if (typeof ref === "function") {
              ref(node);
            } else if (ref) {
              ref.current = node;
            }
            internalModalRef.current = node;
          }}
          className={styles.modal({ placement, width, maxHeight })}
          style={modalStyle}
        >
          <Dialog
            className={styles.dialog({ placement, draggable: isDragEnabled })}
            {...(isDragEnabled ? dragProps : {})}
          >
            {isDragEnabled && (
              <div className={styles.dragIndicatorWrapper} aria-hidden="true">
                <div className={styles.dragIndicator} />
              </div>
            )}
            <ModalContext.Provider
              value={{ placement, onClose: handleClose, bodyRef }}
            >
              {children}
            </ModalContext.Provider>
          </Dialog>
        </AriaModal>
      </ModalOverlay>
    );
  }
);

ModalRoot.displayName = "Modal";

// ============================================================================
// Compound Component Export
// ============================================================================

export const Modal = Object.assign(ModalRoot, {
  Header: ModalHeader,
  Body: ModalBody,
  Footer: ModalFooter,
});
